import React, { useState, useRef, useEffect, useMemo } from 'react';
import Fuse from 'fuse.js';
import { motion, AnimatePresence } from 'framer-motion';
import {
  MessageSquare,
  Search,
  History,
  Mic,
  Square,
  Play,
  Sparkles,
  Trash2,
  Calendar,
  ChevronRight,
  Wind,
  BarChart3,
  X,
  LayoutDashboard,
  LogOut,
  ArrowLeft,
  User,
  ClipboardList,
  Plus
} from 'lucide-react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  AreaChart,
  Area
} from 'recharts';
import './index.css';

const API_BASE_URL = 'http://localhost:5000';

function App() {
  // Autenticação e Perfis
  const [usuario, setUsuario] = useState(() => {
    const saved = localStorage.getItem('usuario');
    return saved ? JSON.parse(saved) : null;
  });

  const [authMode, setAuthMode] = useState('login'); // 'login' or 'cadastro'
  const [authTipo, setAuthTipo] = useState('paciente'); // 'paciente' or 'psicologo'
  const [authNome, setAuthNome] = useState('');
  const [authEmail, setAuthEmail] = useState('');
  const [authSenha, setAuthSenha] = useState('');
  const [authPsicologoId, setAuthPsicologoId] = useState('');
  const [listaPsicologos, setListaPsicologos] = useState([]);

  // Estados do Chat e Histórico (Paciente)
  const [gravando, setGravando] = useState(false);
  const [transcricao, setTranscricao] = useState('');
  const [exercicio, setExercicio] = useState('');
  const [carregando, setCarregando] = useState(false);
  const [historico, setHistorico] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [sessaoAtiva, setSessaoAtiva] = useState(null);
  const [currentView, setCurrentView] = useState('app'); // 'app', 'dashboard', 'agenda', 'financeiro', 'prontuario'
  const [showSOS, setShowSOS] = useState(false);
  const [breathingStep, setBreathingStep] = useState('Inspire');
  const [falando, setFalando] = useState(false);

  // Estados do Psicólogo
  const [listaPacientes, setListaPacientes] = useState([]);
  const [pacienteSelecionado, setPacienteSelecionado] = useState(null);

  // Cadastro de Paciente pelo Psicólogo
  const [showNovoPacienteForm, setShowNovoPacienteForm] = useState(false);
  const [novoPacNome, setNovoPacNome] = useState('');
  const [novoPacEmail, setNovoPacEmail] = useState('');
  const [novoPacSenha, setNovoPacSenha] = useState('');

  // Estados para Agenda (Fase 3)
  const [listaConsultas, setListaConsultas] = useState([]);
  const [dataSelecionada, setDataSelecionada] = useState('');
  const [horariosDisponiveis, setHorariosDisponiveis] = useState([]);
  const [horarioSelecionado, setHorarioSelecionado] = useState('');
  const [obsConsulta, setObsConsulta] = useState('');
  const [pacienteConsultaId, setPacienteConsultaId] = useState(''); // Usado na visão geral do Psicólogo para agendar

  // Estados para Financeiro (Fase 4)
  const [financeiroData, setFinanceiroData] = useState({ lancamentos: [], resumo: { total_receitas: 0, total_despesas: 0, lucro_liquido: 0 } });
  const [listaPacotes, setListaPacotes] = useState([]);

  // Formulário Financeiro
  const [finTipo, setFinTipo] = useState('receita'); // 'receita' or 'despesa'
  const [finCategoria, setFinCategoria] = useState('sessao');
  const [finValor, setFinValor] = useState('');
  const [finDescricao, setFinDescricao] = useState('');
  const [finStatus, setFinStatus] = useState('pago');
  const [finPacienteId, setFinPacienteId] = useState('');

  // Venda de Pacote
  const [pacSessoes, setPacSessoes] = useState('4');
  const [pacValorTotal, setPacValorTotal] = useState('');

  // Prontuário IA Consolidado (Novo)
  const [prontuarioConteudo, setProntuarioConteudo] = useState('');
  const [prontuarioData, setProntuarioData] = useState('');
  const [gerandoProntuario, setGerandoProntuario] = useState(false);

  // Notas Clínicas do Psicólogo
  const [listaNotas, setListaNotas] = useState([]);
  const [novaNotaConteudo, setNovaNotaConteudo] = useState('');
  const [carregandoNotas, setCarregandoNotas] = useState(false);

  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);
  const audioContextRef = useRef(null);

  // Carregar psicólogos para a tela de cadastro de pacientes
  useEffect(() => {
    if (authMode === 'cadastro' && authTipo === 'paciente') {
      fetch(`${API_BASE_URL}/psicologos`)
        .then(res => res.json())
        .then(data => {
          setListaPsicologos(data);
          if (data.length > 0) setAuthPsicologoId(data[0].id);
        })
        .catch(err => console.error("Erro ao buscar psicólogos:", err));
    }
  }, [authMode, authTipo]);

  // Carregar dados gerais ao iniciar
  useEffect(() => {
    if (usuario) {
      fetchConsultas();
      fetchFinanceiro();
      if (usuario.tipo === 'paciente') {
        fetchHistorico();
        fetchPacotes();
      } else if (usuario.tipo === 'psicologo') {
        fetchPacientes();
      }
    }
  }, [usuario]);

  // Carregar histórico, pacotes e prontuário IA do paciente selecionado
  useEffect(() => {
    if (usuario && usuario.tipo === 'psicologo' && pacienteSelecionado) {
      fetchHistorico(pacienteSelecionado.id);
      fetchPacotes(pacienteSelecionado.id);
      fetchConsultas();
      fetchProntuarioIA(pacienteSelecionado.id);
      fetchNotas(pacienteSelecionado.id);
    } else {
      setHistorico([]);
      setListaPacotes([]);
      setProntuarioConteudo('');
      setProntuarioData('');
      setListaNotas([]);
    }
    setSessaoAtiva(null);
    setTranscricao('');
    setExercicio('');
    setCurrentView('app'); // Reseta a aba interna ao trocar paciente
    setShowNovoPacienteForm(false); // Fecha cadastro se abrir paciente
  }, [pacienteSelecionado]);

  // Carregar horários livres quando a data mudar
  useEffect(() => {
    if (dataSelecionada) {
      fetchHorariosDisponiveis(dataSelecionada);
    } else {
      setHorariosDisponiveis([]);
    }
  }, [dataSelecionada]);

  // Fetch Handlers

  const fetchHistorico = async (pacienteId = null) => {
    if (!usuario) return;
    try {
      let url = `${API_BASE_URL}/historico`;
      if (usuario.tipo === 'psicologo' && pacienteId) {
        url += `?paciente_id=${pacienteId}`;
      }

      const resp = await fetch(url, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      setHistorico(data.map(item => ({
        ...item,
        sentimento: item.sentimento || 'Neutro'
      })));
    } catch (err) {
      console.error("Erro ao carregar histórico:", err);
    }
  };

  const fetchPacientes = async () => {
    if (!usuario || usuario.tipo !== 'psicologo') return;
    try {
      const resp = await fetch(`${API_BASE_URL}/pacientes`, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      setListaPacientes(data);
    } catch (err) {
      console.error("Erro ao carregar pacientes:", err);
    }
  };

  const fetchConsultas = async () => {
    if (!usuario) return;
    try {
      let url = `${API_BASE_URL}/consultas`;
